
DROP TABLE IF EXISTS imp_loans_update;

CREATE TABLE imp_loans_update(
	imp_loans_update_id		        serial primary key,
	transaction_ref					varchar(100) not null, 
	account_ref		 				varchar(256) not null,
	loans_date						varchar(25),
	account_name					varchar(256),
	debit							decimal(10,2) default null,
	credit							decimal(10,2) default null,
	principle						real,
	charge							real,
	new_client						boolean not null,
	updated							boolean default true not null
);

